import org.jsoup.Jsoup;
import org.jsoup.safety.Whitelist;

public class XSSSecureCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Sanitizing user input to prevent XSS attacks
        String sanitizedInput = Jsoup.clean(userInput, Whitelist.basic());

        // Displaying sanitized user input
        System.out.println("User input: " + sanitizedInput);
    }
}

